    public static ReceivableRepayment deploy(Client client, CryptoKeyPair credential, String _admin,
            String _receivableCore) throws ContractException {
        @SuppressWarnings("rawtypes")
        byte[] encodedConstructor = FunctionEncoder.encodeConstructor(Arrays.<Type>asList(new org.fisco.bcos.sdk.v3.codec.datatypes.Address(_admin), 
                new org.fisco.bcos.sdk.v3.codec.datatypes.Address(_receivableCore)));
        ReceivableRepayment contract = deploy(ReceivableRepayment.class, client, credential, getBinary(client.getCryptoSuite()), getABI(), encodedConstructor, null);
        contract.setTransactionManager(new ProxySignTransactionManager(client));
        return contract;
    }

